  const from = aiPeople().find((x) => x.id === (payload && payload.fromId));
  if (!into || !from || into === from) return { ok: false };
  into.faces = capFacesKeepingConfirmed([...(into.faces || []), ...(from.faces || [])], 60);   // #49 — confirmed-first
